#include &lt;stdint.h&gt;
#include &lt;stdlib.h&gt;
#include &lt;stdio.h&gt;

typedef struct {
    uint8_t *buffer;      // Massive pre-allocated backing memory
    size_t capacity;      // Total size
    size_t current_offset;// Current high-water mark
} Arena;

Arena* arena_create(size_t size) {
    Arena *a = malloc(sizeof(Arena));
    a->buffer = malloc(size);
    a->capacity = size;
    a->current_offset = 0;
    return a;
}

void* arena_alloc(Arena *a, size_t size) {
    // 1. Hardware Alignment: CPUs hate unaligned reads.
    // We MUST manually pad the requested size to an 8-byte boundary.
    size_t aligned_size = (size + 7) & ~7;

    // 2. Bounds checking
    if (a->current_offset + aligned_size > a->capacity) {
        return NULL; // OOM
    }

    // 3. O(1) Allocation
    void *ptr = a->buffer + a->current_offset;
    a->current_offset += aligned_size;
    return ptr;
}

void arena_reset(Arena *a) {
    // 4. O(1) Deallocation of the ENTIRE arena
    a->current_offset = 0;
}

#include &lt;stdint.h&gt;

// A naive arena allocator without alignment logic
void* naive_alloc(Arena *a, size_t size) {
    void *ptr = a->buffer + a->current_offset;
    a->current_offset += size;
    return ptr;
}

int main() {
    Arena *a = arena_create(1024);

    // Engineer allocates a 3-byte string
    char *str = naive_alloc(a, 3);

    // Engineer immediately allocates a 64-bit integer
    uint64_t *timestamp = naive_alloc(a, sizeof(uint64_t));

    // CRASH: Writing triggers a SIGBUS on strict architectures
    *timestamp = 1684992000;
    return 0;
}

