#include &lt;stdint.h&gt;
#include &lt;stdlib.h&gt;
#include &lt;stdio.h&gt;

// We must cast the raw blocks to this FreeNode struct to weave our linked list.
typedef struct FreeNode {
    struct FreeNode *next;
} FreeNode;

typedef struct {
    uint8_t *buffer;   // The massive contiguous RAM block
    size_t chunk_size; // Exact size of each object
    FreeNode *head;    // Pointer to the first available block
} ObjectPool;

ObjectPool* pool_create(size_t chunk_size, size_t count) {
    ObjectPool *p = malloc(sizeof(ObjectPool));

    // Force alignment to 8 bytes, ensuring a pointer can fit inside safely
    p->chunk_size = (chunk_size >= 8) ? chunk_size : 8;
    p->buffer = malloc(p->chunk_size * count);

    // Thread the initial Free List sequentially through every block
    p->head = (FreeNode *)p->buffer;
    for (size_t i = 0; i < count - 1; i++) {
        FreeNode *current = (FreeNode *)(p->buffer + (i * p->chunk_size));
        FreeNode *next    = (FreeNode *)(p->buffer + ((i + 1) * p->chunk_size));
        current->next = next;
    }

    // Terminate the final block
    ((FreeNode *)(p->buffer + ((count - 1) * p->chunk_size)))->next = NULL;
    return p;
}

void* pool_alloc(ObjectPool *p) {
    if (p->head == NULL) return NULL; // Pool Empty

    // O(1) Pop from the Head of the Free List
    FreeNode *block = p->head;
    p->head = block->next; // Advance head
    return block;          // Hand block to application
}

void pool_free(ObjectPool *p, void *ptr) {
    // O(1) Push back onto the Head of the Free List
    FreeNode *block = (FreeNode *)ptr;
    block->next = p->head;
    p->head = block;
}

typedef struct {
    int access_level;
    char name[32];
} UserSession;

int main() {
    ObjectPool *pool = pool_create(sizeof(UserSession), 10);

    // 1. User logs in, gets a session, modifies it
    UserSession *u1 = pool_alloc(pool);
    u1->access_level = 99; // Admin

    // 2. User logs out
    pool_free(pool, u1);

    // 3. New anonymous user logs in
    UserSession *u2 = pool_alloc(pool);

    // DANGER: What is u2->access_level?
    return 0;
}
